SELECT * FROM review_records
WHERE project_id = #{projectId}
  AND created_at BETWEEN #{from} AND #{to}
ORDER BY created_at DESC

SELECT * FROM review_records
WHERE project_id = #{projectId}
  AND created_at >= #{since}
ORDER BY created_at DESC

SELECT COUNT(*) FROM review_records
WHERE project_id = #{projectId}
  AND created_at BETWEEN #{from} AND #{to}
  AND has_blocking = TRUE
